update public.cbt_questions set intent_ko = '치매 환자 주보호자의 스트레스와 감정을 공감하는 적절한 의사소통 방법을 묻는 문제', intent_vi = 'Câu hỏi về cách giao tiếp phù hợp để thấu hiểu cảm xúc và stress của người chăm sóc chính bệnh nhân Alzheimer', choice_explanations = '{"ko": {"1": "남편에게 대립적인 행동을 유도하여 가족 갈등을 악화시킬 수 있는 부적절한 대응입니다.", "2": "★ 주보호자의 감정을 있는 그대로 인정하고 공감하는 올바른 의사소통 방법입니다. 요양보호사는 보호자의 심리적 부담을 이해하고 경청하는 자세로 정서적 지지를 제공해야 합니다. ''가족들이 몰라주는 것 같아 속상하시겠어요''라는 말은 보호자의 감정을 수용하고 공감하며, 보호자가 자신의 감정을 표현할 수 있도록 돕습니다.", "3": "딸에 대한 부정적 평가로 가족 간 관계를 악화시킬 수 있는 부적절한 대응입니다.", "4": "보호자의 어려움을 무시하고 참으라고 강요하는 것은 감정을 억압시키고 스트레스를 가중시킵니다.", "5": "요양보호사가 직접 가족 문제에 개입하는 것은 전문적 경계를 넘는 부적절한 행동입니다."}, "vi": {"1": "Phản ứng không phù hợp vì khuyến khích hành động đối đầu với chồng, có thể làm xấu đi mối quan hệ gia đình.", "2": "★ Đây là cách giao tiếp đúng để thừa nhận và thấu hiểu cảm xúc của người chăm sóc chính. Nhân viên chăm sóc phải hiểu gánh nặng tâm lý của người chăm sóc, lắng nghe và hỗ trợ tinh thần. Câu nói ''Chị chắc buồn vì gia đình không hiểu cho chị'' thể hiện sự đồng cảm, chấp nhận cảm xúc của người chăm sóc và giúp họ được bộc lộ cảm xúc.", "3": "Phản ứng không phù hợp vì đánh giá tiêu cực về con gái, có thể làm xấu mối quan hệ gia đình.", "4": "Việc phủ nhận khó khăn của người chăm sóc và bắt họ chịu đựng sẽ gây thêm stress và ức chế cảm xúc.", "5": "Việc nhân viên chăm sóc trực tiếp can thiệp vào vấn đề gia đình là hành vi vượt qua ranh giới chuyên môn."}}'::jsonb, key_terms = '[{"term_ko": "주보호자", "def_vi": "Người chăm sóc chính - người trực tiếp chăm sóc bệnh nhân nhiều nhất"}, {"term_ko": "치매", "def_vi": "Bệnh Alzheimer - bệnh suy giảm trí nhớ và nhận thức"}, {"term_ko": "공감", "def_vi": "Sự đồng cảm - hiểu và chia sẻ cảm xúc của người khác"}, {"term_ko": "정서적 지지", "def_vi": "Hỗ trợ tinh thần - động viên và an ủi về mặt cảm xúc"}]'::jsonb where id = 1740;
update public.cbt_questions set intent_ko = '치매 대상자가 환각(없는 사람을 보는 증상)을 보일 때 올바른 대처 방법을 묻는 문제', intent_vi = 'Câu hỏi về cách xử lý đúng khi người bệnh Alzheimer có triệu chứng ảo giác (nhìn thấy người không tồn tại)', choice_explanations = '{"ko": {"1": "대상자의 환각 증상을 직접적으로 부정하면 불안과 혼란이 더 심해질 수 있습니다. 대상자가 보고 있는 것이 실제라고 느끼기 때문에 ''없다''는 말은 신뢰를 깨뜨립니다.", "2": "함께 소리를 지르면 대상자의 불안과 흥분 상태를 더욱 악화시켜 상황을 통제하기 어려워집니다.", "3": "혼내려고 왔다는 말은 대상자에게 공포와 죄책감을 유발하여 정서적 안정에 해롭습니다.", "4": "★ 환각 증상이 나타날 때는 대상자의 주의를 다른 곳으로 전환시키는 것이 가장 효과적입니다. 좋아하는 간식을 주거나 즐겨하는 활동(음악 듣기, 산책 등)을 제안하면 불안이 감소하고 안정을 찾을 수 있습니다. 이는 비약물적 중재의 핵심 원칙입니다.", "5": "헛것이 보인다고 직접 말하면 대상자가 자신의 상태를 부정적으로 인식하게 되어 불안과 좌절감이 증가합니다."}, "vi": {"1": "Phủ nhận trực tiếp triệu chứng ảo giác của người bệnh có thể làm tăng lo lắng và nhầm lẫn. Vì người bệnh cảm thấy những gì họ nhìn thấy là thật, nên nói ''không có ai'' sẽ phá vỡ lòng tin.", "2": "Hét cùng người bệnh sẽ làm trầm trọng thêm trạng thái lo lắng và kích động, khiến tình huống khó kiểm soát hơn.", "3": "Nói rằng ai đó đến để la mắng sẽ gây ra nỗi sợ hãi và cảm giác tội lỗi cho người bệnh, có hại cho sự ổn định tinh thần.", "4": "★ Khi có triệu chứng ảo giác, cách hiệu quả nhất là chuyển hướng sự chú ý của người bệnh sang việc khác. Đưa đồ ăn nhẹ yêu thích hoặc đề nghị hoạt động họ thích (nghe nhạc, đi dạo) sẽ giảm lo lắng và giúp người bệnh ổn định. Đây là nguyên tắc cốt lõi của can thiệp không dùng thuốc.", "5": "Nói trực tiếp rằng họ nhìn thấy ảo giác sẽ khiến người bệnh nhận thức tiêu cực về tình trạng của mình, làm tăng lo lắng và cảm giác thất vọng."}}'::jsonb, key_terms = '[{"term_ko": "환각", "def_vi": "Ảo giác - nhìn thấy, nghe thấy thứ không tồn tại thực tế"}, {"term_ko": "비약물적 중재", "def_vi": "Can thiệp không dùng thuốc - phương pháp điều trị không sử dụng dược phẩm"}, {"term_ko": "주의 전환", "def_vi": "Chuyển hướng chú ý - làm người bệnh tập trung vào việc khác"}, {"term_ko": "정서적 안정", "def_vi": "Sự ổn định tinh thần/cảm xúc"}]'::jsonb where id = 1739;

